CREATE OR REPLACE FUNCTION public._assert_strategy_visible_to_allocator(
  p_strategy_id UUID,
  p_allocator_id UUID
)
RETURNS BOOLEAN
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
